package com.spendwise.prototype.ui; import android.content.Intent; import android.os.Bundle; import android.view.View; import android.widget.TextView; import androidx.fragment.app.Fragment; import androidx.lifecycle.lifecycleScope; import androidx.recyclerview.widget.LinearLayoutManager; import androidx.recyclerview.widget.RecyclerView; import com.spendwise.prototype.R; import com.spendwise.prototype.data.AppDatabase; import kotlinx.coroutines.flow.combine; import kotlinx.coroutines.launch; import java.util.*; class ExpensesListFragment:Fragment(R.layout.fragment_expenses){ override fun onViewCreated(v:View,b:Bundle?){ val db=AppDatabase.get(requireContext()); val rv=v.findViewById<RecyclerView>(R.id.rvExpenses); rv.layoutManager=LinearLayoutManager(context); val ad=ExpenseAdapter{ e-> e.photoPath?.let{ p-> startActivity(Intent(requireContext(),PhotoViewerActivity::class.java).putExtra("photo_path",p)) } }; rv.adapter=ad; val c=Calendar.getInstance(); c.set(Calendar.DAY_OF_MONTH,1); val s=c.timeInMillis; val e=System.currentTimeMillis(); lifecycleScope.launch{ combine(db.expenseDao().between(s,e),db.expenseDao().totalsPerCategory(s,e)){l,t->Pair(l,t)}.collect{ (l,t)-> ad.submitList(l); v.findViewById<TextView>(R.id.tvGrandTotal).text="Total: R%.2f".format(l.sumOf{it.amount}); v.findViewById<TextView>(R.id.tvTotals).text=t.joinToString("\n"){ "Cat ${it.categoryId}: R%.2f".format(it.total) } } } } }